import { Effect, Data } from "effect";

interface User { readonly id: string; readonly name: string }

class UserNotFound extends Data.TaggedError("UserNotFound")<{ readonly id: string }> {}
class DbUnavailable extends Data.TaggedError("DbUnavailable")<{ readonly host: string }> {}

declare const fetchUser: (id: string) => Effect.Effect<User, UserNotFound | DbUnavailable>;

export const findOrGuest = (id: string): Effect.Effect<User, DbUnavailable> =>
  fetchUser(id).pipe(
    Effect.catchTag("UserNotFound", () => Effect.succeed<User>({ id: "guest", name: "Guest" }))
