Add a retry-on-transient capability to this Effect program that can fail with RateLimited or Unauthorized — recover from RateLimited by waiting, and let Unauthorized bubble out.

```ts
import { Effect, Data } from "effect";
class RateLimited extends Data.TaggedError("RateLimited")<{ retryAfter: number }> {}
class Unauthorized extends Data.TaggedError("Unauthorized")<{}> {}
declare const apiCall: () => Effect.Effect<string, RateLimited | Unauthorized>;
```

```ts
import { Effect, Data, Duration } from "effect";

class RateLimited extends Data.TaggedError("RateLimited")<{ readonly retryAfter: number }> {}
class Unauthorized extends Data.TaggedError("Unauthorized")<{}> {}

declare const apiCall: () => Effect.Effect<string, RateLimited | Unauthorized>;

export const resilientCall: Effect.Effect<string, Unauthorized> = apiCall().pipe(
  Effect.catchTag("RateLimited", (e) =>
    Effect.sleep(Duration.seconds(e.retryAfter)).pipe(Effect.andThen(apiCall()))
  ),
  Effect.catchTag("RateLimited", () => Effect.succeed(""))
);
```

The first `catchTag` waits and re-invokes, which can itself still fail with `RateLimited`; the second pass guarantees the final type strips that tag, leaving only `Unauthorized` in `E`.

