import { Effect } from "effect";

interface Config { readonly port: number; readonly host: string }

class ParseError { readonly _tag = "ParseError" as const; constructor(readonly raw: string) {} }
class ValidationError { readonly _tag = "ValidationError" as const; constructor(readonly field: string) {} }

declare const parse: (s: string) => Effect.Effect<unknown, ParseError>;
declare const validate: (u: unknown) => Effect.Effect<Config, ValidationError>;

export const loadConfig = (input: string): Effect.Effect<Config, ValidationError> =>
  Effect.gen(function* () {
    const raw = yield* parse(input);
    const cfg = yield* validate(raw);
    return cfg;
  }).pipe(
    Effect.catchTag("ParseError", () =>
      Effect.succeed<Config>({ port: 8080, host: "localhost" })
    )
  );
```

The literal `_tag = "..." as const` form is the minimum needed for `Effect.catchTag` to discriminate; the remaining `ValidationError` stays in the `E` channel after the catch.

