Fix this Effect v3 code — it uses raw Error instead of tagged errors, which prevents catchTag from working:

```ts
const lookup = (id: string) => Effect.tryPromise(() => fetch('/u/'+id));
const recover = lookup('x').pipe(Effect.catchAll(() => Effect.succeed('default')))
```

```ts
import { Effect, Data } from "effect";

class NetworkError extends Data.TaggedError("NetworkError")<{ readonly cause: unknown }> {}
class NotFoundError extends Data.TaggedError("NotFoundError")<{ readonly id: string }> {}

const lookup = (id: string): Effect.Effect<string, NetworkError | NotFoundError> =>
  Effect.tryPromise({
    try: () => fetch("/u/" + id).then((r) => r.text()),
    catch: (cause) => new NetworkError({ cause }),
  });

export const recover = (id: string): Effect.Effect<string, NetworkError> =>
  lookup(id).pipe(
    Effect.catchTag("NotFoundError", () => Effect.succeed("default"))
  );
```

Replacing the raw `Error` with `Data.TaggedError` classes enables `Effect.catchTag` to discriminate on `_tag`; `catchAll` would have erased type information, whereas `catchTag` preserves `NetworkError` in the `E` channel.

```ts
import { Effect } from "effect";

class MalformedUrl { readonly _tag = "MalformedUrl" as const; constructor(readonly input: string) {} }
class UnsupportedScheme { readonly _tag = "UnsupportedScheme" as const; constructor(readonly scheme: string) {} }

declare const parseUrl: (s: string) => Effect.Effect<URL, MalformedUrl | UnsupportedScheme>;

export const parseOrDefault = (s: string): Effect.Effect<URL, UnsupportedScheme> =>
  parseUrl(s).pipe(
    Effect.catchTag("MalformedUrl", () => Effect.succeed(new URL("https://example.com")))
  );
```

Each `Effect.catchTag(tag, handler)` call is the typed analogue of a single `catch` clause — it peels off one discriminated case and the rest remain in the `E` channel.

