```ts
import { Effect, Data } from "effect";

interface Order { readonly id: string; readonly total: number }
interface Shipment { readonly trackingId: string }

class OutOfStock extends Data.TaggedError("OutOfStock")<{ readonly sku: string }> {}
class PaymentDeclined extends Data.TaggedError("PaymentDeclined")<{ readonly card: string }> {}
class ShippingUnavailable extends Data.TaggedError("ShippingUnavailable")<{ readonly zip: string }> {}

declare const reserve: (sku: string) => Effect.Effect<Order, OutOfStock>;
declare const charge: (o: Order, card: string) => Effect.Effect<void, PaymentDeclined>;
declare const ship: (o: Order, zip: string) => Effect.Effect<Shipment, ShippingUnavailable>;

const altCard = "alt-4242";

export const checkout = (
  sku: string,
  card: string,
  zip: string
): Effect.Effect<Shipment, OutOfStock | ShippingUnavailable> =>
  Effect.gen(function* () {
    const order = yield* reserve(sku);
    yield* charge(order, card).pipe(
      Effect.catchTag("PaymentDeclined", () => charge(order, altCard)),
      Effect.catchTag("PaymentDeclined", () => Effect.void)
    );
    const shipment = yield* ship(order, zip);
    return shipment;
  });
```

The inner `catchTag` retries on an alt card; a second pass erases any remaining `PaymentDeclined` so only `OutOfStock | ShippingUnavailable` survives to the outer signature.

