`Effect.catchTag("Foo", handler)` takes an effect whose error channel is a union and returns a new effect where the `Foo` branch has been replaced by the handler's own error type. Other branches are passed through unchanged.

```ts
import { Effect, Data } from "effect";

class HttpTimeout extends Data.TaggedError("HttpTimeout")<{ readonly ms: number }> {}
class HttpStatus extends Data.TaggedError("HttpStatus")<{ readonly status: number }> {}

declare const req: () => Effect.Effect<string, HttpTimeout | HttpStatus>;

export const withRetryOnTimeout: Effect.Effect<string, HttpStatus> = req().pipe(
  Effect.catchTag("HttpTimeout", () => req()),
  Effect.catchTag("HttpTimeout", () => Effect.succeed(""))
);
```

The first `catchTag` retries once and may re-introduce `HttpTimeout`; the second fully resolves it, leaving only `HttpStatus` in `E`.

```ts
import { Effect, Data, Console } from "effect";

interface Msg { readonly id: string; readonly body: string }
interface Ack { readonly id: string }

class ParseError extends Data.TaggedError("ParseError")<{ readonly raw: string }> {}
class HandlerError extends Data.TaggedError("HandlerError")<{ readonly id: string }> {}
class AckError extends Data.TaggedError("AckError")<{ readonly id: string }> {}

declare const parse: (raw: string) => Effect.Effect<Msg, ParseError>;
declare const handle: (m: Msg) => Effect.Effect<void, HandlerError>;
declare const ack: (m: Msg) => Effect.Effect<Ack, AckError>;

export const consume = (
  raw: string
): Effect.Effect<Ack | "skipped", HandlerError | AckError> =>
  Effect.gen(function* () {
    const m = yield* parse(raw);
    yield* handle(m);
    return yield* ack(m);
  }).pipe(
    Effect.catchTag("ParseError", (e) =>
      Console.warn(`bad message: ${e.raw}`).pipe(Effect.as("skipped" as const))
    )
  );
```

Only `ParseError` is absorbed (into a "skipped" success); `HandlerError` and `AckError` remain in the error channel for the supervisor to observe.

