declare const loadRemote: (
  url: string
) => Effect.Effect<Config, ConfigMissing | ConfigMalformed | NetError>;

export const getConfig = (url: string): Effect.Effect<Config, NetError> =>
  loadRemote(url).pipe(
    Effect.catchTags({
      ConfigMissing: () => Effect.succeed(defaults),
      ConfigMalformed: () => Effect.succeed(defaults),
    })
  );
```

Both config tags share a recovery policy so `catchTags` collapses them in one place; `NetError` survives as the only tag in the returned `E` channel.

```ts
import { Effect, Data } from "effect";

interface Processed { readonly path: string; readonly lines: number }

class FileMissing extends Data.TaggedError("FileMissing")<{ readonly path: string }> {}
class ReadFailed extends Data.TaggedError("ReadFailed")<{ readonly path: string }> {}
class EncodingError extends Data.TaggedError("EncodingError")<{ readonly path: string }> {}

declare const process: (
  path: string
) => Effect.Effect<Processed, FileMissing | ReadFailed | EncodingError>;

export const processOrSkip = (
  path: string
): Effect.Effect<Processed, ReadFailed | EncodingError> =>
  process(path).pipe(
    Effect.catchTag("FileMissing", () =>
      Effect.succeed<Processed>({ path, lines: 0 })
    )
  );
```

`catchTag` is a union-level filter; the remaining tags are automatically carried through in the result's error type by TypeScript's structural subtraction on literal-tag unions.

```ts
import { Effect, Data } from "effect";

class Missing extends Data.TaggedError("Missing")<{ readonly key: string }> {}
class Forbidden extends Data.TaggedError("Forbidden")<{ readonly reason: string }> {}

declare const program: Effect.Effect<string, Missing | Forbidden>;

export const safe: Effect.Effect<string, Forbidden> = program.pipe(
  Effect.catchTag("Missing", () => Effect.succeed("x"))
);
```

Letting TS infer by removing the `unknown` annotation (or annotating as `Effect<string, Forbidden>`) lets `catchTag`'s precise overload subtract `Missing` from the union; the previous `unknown` widened it and defeated the check.

```ts
import { Effect, Data } from "effect";

interface Resource { readonly id: string; readonly data: string }

class PrimaryDown extends Data.TaggedError("PrimaryDown")<{}> {}
class CacheStale extends Data.TaggedError("CacheStale")<{ readonly key: string }> {}
class CacheMiss extends Data.TaggedError("CacheMiss")<{ readonly key: string }> {}

declare const primary: (id: string) => Effect.Effect<Resource, PrimaryDown>;
declare const fromCache: (id: string) => Effect.Effect<Resource, CacheStale | CacheMiss>;

export const fetchResource = (
  id: string
): Effect.Effect<Resource, CacheStale | CacheMiss> =>
  primary(id).pipe(Effect.catchTag("PrimaryDown", () => fromCache(id)));
```

When `PrimaryDown` fires, the handler returns the cache effect, so the combined error type becomes the cache's errors — `PrimaryDown` no longer appears in the outer `E`.

```ts
import { Effect, Data } from "effect";

interface Coords { readonly lat: number; readonly lng: number }

class AddressInvalid extends Data.TaggedError("AddressInvalid")<{ readonly input: string }> {}
class ServiceDown extends Data.TaggedError("ServiceDown")<{}> {}
class QuotaExceeded extends Data.TaggedError("QuotaExceeded")<{ readonly resetAt: number }> {}

declare const geocode: (
  s: string
) => Effect.Effect<Coords, AddressInvalid | ServiceDown | QuotaExceeded>;

export const geocodeSafe = (
